initial_candidates.sql:
SELECT CASE WHEN Harlan.Reputation > Jarrod.Reputation THEN 'Harlan' ELSE 'Jarrod Dixon' END AS HigherReputationUser
FROM users Harlan, users Jarrod
WHERE Harlan.DisplayName = 'Harlan' AND Jarrod.DisplayName = 'Jarrod Dixon';

aggregation.selected_sql:
SELECT CASE WHEN MAX(CASE WHEN DisplayName = 'Harlan' THEN Reputation END) > MAX(CASE WHEN DisplayName = 'Jarrod Dixon' THEN Reputation END) THEN 'Harlan' ELSE 'Jarrod Dixon' END AS HigherReputationUser
FROM users
WHERE DisplayName IN ('Harlan', 'Jarrod Dixon');

